import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { UserSession } from '../../src/entities/user-session.entity';
import { buildUserSession } from '../factories/user-session.factory';
import { User } from '../../src/entities/user.entity';
import { buildUser } from '../factories/user.factory';

describe('UserSession Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<UserSession>;
  let userId: string;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(UserSession);
  });

  beforeEach(async () => {
    const userEntity = await dataSource
      .getRepository(User)
      .save(
        dataSource.getRepository(User).create(
          buildUser(),
        ),
      );
    userId = userEntity.id;
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('belongs_to User', () => {
    it('persists userId reference', async () => {
      const data = buildUserSession({ userId: userId });
      const saved = await repository.save(repository.create(data));
      expect(saved.userId).toBe(userId);
    });

    it('loads parent via relation', async () => {
      const data = buildUserSession({ userId: userId });
      const saved = await repository.save(repository.create(data));
      const loaded = await repository.findOne({
        where: { id: saved.id } as Record<string, unknown>,
        relations: ['user'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.user).toBeDefined();
      expect(loaded!.user.id).toBe(userId);
    });

    it('rejects entity without required userId', async () => {
      const data = buildUserSession({ userId: undefined as unknown as string });
      await expect(
        repository.save(repository.create(data)),
      ).rejects.toThrow();
    });
  });
});
